          }}
        />
      </div>

      <div style={{ marginBottom: "10px", fontWeight: "bold" }}>
        Total: {total}
      </div>

      <table style={{ width: "100%", borderCollapse: "collapse", marginBottom: "20px" }}>
        <thead>
          <tr style={{ backgroundColor: "#f4f4f4", borderBottom: "2px solid #ccc" }}>
            <th style={{ textAlign: "left", padding: "10px", border: "1px solid #ddd" }}>
              <Link
                href={getSortUrl("name")}
                style={{
                  textDecoration: "none",
                  color: "#333",
                  display: "block",
                }}
              >
                Name {sort === "name" ? (dir === "asc" ? "▲" : "▼") : ""}
              </Link>
            </th>
            <th style={{ textAlign: "left", padding: "10px", border: "1px solid #ddd" }}>
              <Link
                href={getSortUrl("category")}
                style={{
                  textDecoration: "none",
                  color: "#333",
                  display: "block",
                }}
              >
                Category {sort === "category" ? (dir === "asc" ? "▲" : "▼") : ""}
              </Link>
            </th>
            <th style={{ textAlign: "left", padding: "10px", border: "1px solid #ddd" }}>
              <Link
                href={getSortUrl("price")}
                style={{
                  textDecoration: "none",
                  color: "#333",
                  display: "block",
                }}
              >
                Price {sort === "price" ? (dir === "asc" ? "▲" : "▼") : ""}
              </Link>
            </th>
            <th style={{ textAlign: "left", padding: "10px", border: "1px solid #ddd" }}>
              <Link
                href={getSortUrl("stock")}
                style={{
                  textDecoration: "none",
                  color: "#333",
                  display: "block",
                }}
              >
                Stock {sort === "stock" ? (dir === "asc" ? "▲" : "▼") : ""}
              </Link>
            </th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id} style={{ borderBottom: "1px solid #ddd" }}>
              <td style={{ padding: "10px", border: "1px solid #ddd" }}>{product.name}</td>
              <td style={{ padding: "10px", border: "1px solid #ddd" }}>{product.category}</td>
              <td style={{ padding: "10px", border: "1px solid #ddd" }}>
                {product.price}
              </td>
              <td style={{ padding: "10px", border: "1px solid #ddd" }}>{product.stock}</td>
            </tr>
          ))}
          {products.length === 0 && (
            <tr>
              <td colSpan={4} style={{ padding: "20px", textAlign: "center", color: "#666" }}>
                No products found
              </td>
            </tr>
          )}
        </tbody>
      </table>

      <div style={{ display: "flex", alignItems: "center", gap: "15px" }}>
        {page > 1 ? (
          <Link
            href={buildUrl({ page: page - 1 })}
            style={{
              padding: "6px 12px",
              border: "1px solid #ccc",
              borderRadius: "4px",
              textDecoration: "none",
              color: "#333",
              backgroundColor: "#fff",
            }}
          >
            Previous
          </Link>
        ) : (
          <span
            style={{
              padding: "6px 12px",
              border: "1px solid #eee",
              borderRadius: "4px",
              color: "#aaa",
              backgroundColor: "#fafafa",
              cursor: "not-allowed",
            }}
          >
            Previous
          </span>
        )}

        <span>
          Page {page} of {totalPages}
        </span>

        {page < totalPages ? (
          <Link
            href={buildUrl({ page: page + 1 })}
            style={{
              padding: "6px 12px",
              border: "1px solid #ccc",
              borderRadius: "4px",
              textDecoration: "none",
              color: "#333",
              backgroundColor: "#fff",
            }}
          >
